// src/pages/RiderRegister.jsx
import React, { useState } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Alert,
  Box,
  Grid,
  Modal,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { signupRider, uploadRiderDocs } from "../services/api";

export default function RiderRegister() {
  const navigate = useNavigate();
  
  // Rider form fields
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    mobile: "",
  });

  // Document files
  const [docs, setDocs] = useState({
    aadharFront: null,
    aadharBack: null,
    license: null,
  });

  // UI states
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [openModal, setOpenModal] = useState(false);

  // Update text fields
  const handleChange = (e) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
  };

  // Update file inputs
  const handleFileChange = (e) => {
    const { name, files } = e.target;
    setDocs((prev) => ({ ...prev, [name]: files[0] }));
  };

  // Form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      // 1️⃣ Signup rider
      const res = await signupRider(formData);
      if (!res.data?.success) {
        setError(res.data?.message || "Signup failed.");
        setLoading(false);
        return;
      }

      const riderId = res.data?.data?.id;
      if (!riderId) {
        setError("No Rider ID returned from server.");
        setLoading(false);
        return;
      }

      // 2️⃣ Upload documents
      const formDataUpload = new FormData();
      formDataUpload.append("aadharFront", docs.aadharFront);
      formDataUpload.append("aadharBack", docs.aadharBack);
      formDataUpload.append("license", docs.license);

      await uploadRiderDocs(riderId, formDataUpload);

      // Show modal popup
      setOpenModal(true);
      setTimeout(() => {
        setOpenModal(false);
        navigate("/rider-login");
      }, 3000);
    } catch (err) {
      console.error("❌ Rider signup error:", err);
      setError("Server error. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper sx={{ mt: 6, p: 5, borderRadius: 4, boxShadow: 3 }}>
        {/* Title */}
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2, textAlign: "center" }}>
          Rider Signup
        </Typography>
        <Typography variant="body2" sx={{ mb: 3, color: "gray", textAlign: "center" }}>
          Join as a rider — create your account and upload documents.
        </Typography>

        {/* Error */}
        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        {/* Form */}
        <form onSubmit={handleSubmit}>
          {/* Text Fields */}
          <TextField
            fullWidth
            label="Full Name"
            name="fullName"
            value={formData.fullName}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            type="email"
            label="Email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            type="tel"
            label="Mobile Number"
            name="mobile"
            value={formData.mobile}
            onChange={handleChange}
            margin="normal"
            inputProps={{ maxLength: 10 }}
            required
          />

          {/* Document Upload */}
          <Typography variant="h6" sx={{ mt: 3, mb: 1 }}>Upload Documents</Typography>
          <Grid container spacing={2}>
            <Grid item xs={12}>
              <Button variant="outlined" component="label" fullWidth>
                Aadhar Front
                <input type="file" name="aadharFront" hidden onChange={handleFileChange} required />
              </Button>
              {docs.aadharFront && <Typography sx={{ mt: 0.5 }}>{docs.aadharFront.name}</Typography>}
            </Grid>
            <Grid item xs={12}>
              <Button variant="outlined" component="label" fullWidth>
                Aadhar Back
                <input type="file" name="aadharBack" hidden onChange={handleFileChange} required />
              </Button>
              {docs.aadharBack && <Typography sx={{ mt: 0.5 }}>{docs.aadharBack.name}</Typography>}
            </Grid>
            <Grid item xs={12}>
              <Button variant="outlined" component="label" fullWidth>
                License
                <input type="file" name="license" hidden onChange={handleFileChange} required />
              </Button>
              {docs.license && <Typography sx={{ mt: 0.5 }}>{docs.license.name}</Typography>}
            </Grid>
          </Grid>

          {/* Submit Button */}
          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ mt: 4, bgcolor: "black", color: "white", fontWeight: "bold" }}
            disabled={loading}
          >
            {loading ? "Submitting..." : "Sign Up"}
          </Button>
        </form>

        {/* Login Link */}
        <Typography sx={{ mt: 3, textAlign: "center" }}>
          Already have an account?{" "}
          <Button onClick={() => navigate("/rider-login")} sx={{ fontWeight: "bold" }}>
            LOGIN
          </Button>
        </Typography>
      </Paper>

      {/* Modal Popup */}
      <Modal open={openModal}>
        <Box
          sx={{
            position: "absolute",
            top: "50%",
            left: "50%",
            transform: "translate(-50%, -50%)",
            bgcolor: "background.paper",
            p: 4,
            borderRadius: 3,
            textAlign: "center",
            boxShadow: 24,
          }}
        >
          <Typography variant="h6" sx={{ mb: 2 }}>Registration Successful!</Typography>
          <Typography>Please wait for admin approval.</Typography>
        </Box>
      </Modal>
    </Container>
  );
}
